CYPHER runtime=interpreted 
UNWIND range(0,4) AS n
WITH toString(n) AS N, '8' as nMax
MATCH (v:VertexNode {Degree:N})<-[vI:VertexIndexedBy]-(i:IndexedByArgument {N:"5",MaxN:nMax,Dimension:'8'})-[]->(e:Evaluate)  
//RETURN i,v
WITH v,i,N,nMax
OPTIONAL MATCH (vXY:VertexNodeXY)<-[vI:VertexIndexedBy]-(iXY:IndexedByXY {Dimension:N,Constant:"8"}) 
//RETURN vXY,iXY,v,i

WITH vXY.Degree AS AADegree,vXY.Scalar AS AAScalar,v.Degree AS TTDegree,v.Scalar AS TTScalar,
CASE WHEN vXY.Degree IS Null THEN v.Degree ELSE apoc.number.exact.add(v.Degree,vXY.Degree) END AS degreeSum,
CASE WHEN vXY.Scalar IS Null THEN toString(v.Scalar) ELSE apoc.number.exact.mul(v.Scalar,vXY.Scalar) END as scalarProduct

RETURN AADegree,AAScalar,TTDegree,TTScalar,degreeSum,scalarProduct

